+// PaneInjectionStats — properties
+// =========================================================================
+
+proptest! {
+    #![proptest_config(ProptestConfig::with_cases(30))]
+
+    /// PaneInjectionStats Debug doesn't panic.
+    #[test]
+    fn prop_stats_debug(stats in arb_pane_stats()) {
+        let debug = format!("{:?}", stats);
